import { describe, expect, it } from "vitest";
import { priceOrder } from "../src/pricing.js";

// Every value below is computed by hand from the spec in src/pricing.js,
// not read off the implementation. Each test names the bug it would catch.

describe("subtotal", () => {
  // Bug: forgetting to multiply unitCents by qty.
  it("multiplies unitCents by qty for a single line", () => {
    expect(priceOrder([{ unitCents: 250, qty: 3 }]).subtotalCents).toBe(750);
  });

  // Bug: overwriting instead of accumulating across lines.
  it("sums across multiple lines", () => {
    const r = priceOrder([
      { unitCents: 250, qty: 3 }, // 750
      { unitCents: 100, qty: 2 }, // 200
    ]);
    expect(r.subtotalCents).toBe(950);
  });

  // Bug: empty cart not yielding all-zero result.
  it("returns all zeros for an empty cart", () => {
    expect(priceOrder([])).toEqual({
      subtotalCents: 0,
      discountCents: 0,
      totalCents: 0,
    });
  });
});

describe("qty validation", () => {
  // Bug: accepting qty <= 0. Boundary just below the valid range.
  it("throws RangeError on qty of 0", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: 0 }])).toThrow(RangeError);
  });

  // Bug: accepting negative qty.
  it("throws RangeError on negative qty", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: -1 }])).toThrow(RangeError);
  });

  // Bug: accepting fractional qty.
  it("throws RangeError on non-integer qty", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: 1.5 }])).toThrow(RangeError);
  });

  // Boundary just above 0: qty of 1 is the smallest valid quantity.
  it("accepts qty of 1", () => {
    expect(priceOrder([{ unitCents: 100, qty: 1 }]).subtotalCents).toBe(100);
  });
});

describe("tier discount", () => {
  // Boundary just below 10000: no tier discount applies.
  it("gives no tier discount at subtotal 9999", () => {
    const r = priceOrder([{ unitCents: 9999, qty: 1 }]);
    expect(r.discountCents).toBe(0);
    expect(r.totalCents).toBe(9999);
  });

  // Boundary exactly at 10000: threshold is >= so tier applies. 10% = 1000.
  it("applies 10% tier discount exactly at subtotal 10000", () => {
    const r = priceOrder([{ unitCents: 10000, qty: 1 }]);
    expect(r.discountCents).toBe(1000);
    expect(r.totalCents).toBe(9000);
  });

  // Boundary just above 10000: 10% of 10001 = 1000.1 -> rounds to 1000.
  it("applies tier discount just above the threshold", () => {
    const r = priceOrder([{ unitCents: 10001, qty: 1 }]);
    expect(r.discountCents).toBe(1000);
    expect(r.totalCents).toBe(9001);
  });

  // Bug: .5 rounding down or truncation. 12345 * 0.1 = 1234.5 -> rounds up to 1235.
  it("rounds tier discount half up", () => {
    const r = priceOrder([{ unitCents: 12345, qty: 1 }]);
    expect(r.discountCents).toBe(1235);
    expect(r.totalCents).toBe(11110);
  });
});

describe("coupon discount", () => {
  // Bug: applying coupon when absent.
  it("no coupon discount when coupon is omitted", () => {
    const r = priceOrder([{ unitCents: 5000, qty: 1 }]);
    expect(r.discountCents).toBe(0);
    expect(r.totalCents).toBe(5000);
  });

  // Straightforward coupon below tier threshold: 20% of 5000 = 1000.
  it("applies coupon pct to subtotal when no tier discount", () => {
    const r = priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 20 });
    expect(r.discountCents).toBe(1000);
    expect(r.totalCents).toBe(4000);
  });

  // Bug: coupon of 0 producing a nonzero discount.
  it("treats a 0% coupon as no discount", () => {
    const r = priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 0 });
    expect(r.discountCents).toBe(0);
    expect(r.totalCents).toBe(5000);
  });

  // Bug: coupon computed on the pre-tier subtotal instead of after tier.
  // subtotal 10000, tier 1000, remaining 9000, 30% coupon = 2700.
  it("applies coupon to subtotal AFTER the tier discount", () => {
    const r = priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 30 });
    expect(r.discountCents).toBe(3700);
    expect(r.totalCents).toBe(6300);
  });

  // Bug: .5 coupon rounding down/truncation. 1005 * 0.10 = 100.5 -> 101.
  it("rounds coupon discount half up", () => {
    const r = priceOrder([{ unitCents: 1005, qty: 1 }], { pct: 10 });
    expect(r.discountCents).toBe(101);
    expect(r.totalCents).toBe(904);
  });
});

describe("coupon cap at 30%", () => {
  // Boundary exactly at 30: not capped. 30% of 1000 = 300.
  it("does not cap a 30% coupon", () => {
    const r = priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 30 });
    expect(r.discountCents).toBe(300);
  });

  // Boundary just above 30: capped to 30. 31 would give 310, cap gives 300.
  it("caps a 31% coupon at 30%", () => {
    const r = priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 31 });
    expect(r.discountCents).toBe(300);
  });

  // Far above cap: 100% still capped to 30%.
  it("caps a 100% coupon at 30%", () => {
    const r = priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 100 });
    expect(r.discountCents).toBe(300);
    expect(r.totalCents).toBe(700);
  });
});

describe("combined tier and coupon", () => {
  // Bug: mis-summing the two discounts, or wrong total.
  // subtotal 20000, tier 2000, remaining 18000, 30% = 5400, discount 7400.
  it("sums tier and coupon discounts", () => {
    const r = priceOrder([{ unitCents: 10000, qty: 2 }], { pct: 30 });
    expect(r).toEqual({
      subtotalCents: 20000,
      discountCents: 7400,
      totalCents: 12600,
    });
  });
});

